 {"id":"rust_proxy-ow9","title":"Unit tests for Config Watch/Reload","description":"## Unit Tests for Config Watch/Reload

### Test Coverage Areas

1. **Config Diff Logic**
   ```rust
   #[test]
   fn test_diff_detects_added_proxy() {
       let old = config_with_proxies(&["a", "b"]);
       let new = config_with_proxies(&["a", "b", "c"]);
       let diff = ConfigDiff::compute(&old, &new);
       assert_eq!(diff.added_proxies, vec!["c"]);
       assert!(diff.removed_proxies.is_empty());
       assert!(diff.modified_proxies.is_empty());
   }

   #[test]
   fn test_diff_detects_removed_proxy() {
       let old = config_with_proxies(&["a", "b", "c"]);
       let new = config_with_proxies(&["a", "c"]);
       let diff = ConfigDiff::compute(&old, &new);
       assert_eq!(diff.removed_proxies, vec!["b"]);
   }

   #[test]
   fn test_diff_detects_modified_settings() {
       let old = config_with_interval(30);
       let new = config_with_interval(60);
       let diff = ConfigDiff::compute(&old, &new);
       assert!(diff.settings_changed);
       assert!(diff.changed_settings.contains("health_check_interval_secs"));
   }
   ```

2. **Config Validation**
   ```rust
   #[test]
   fn test_validates_new_config_before_reload() {
       let validator = ConfigValidator::new();
       let invalid = "[[proxies]]"; // missing required fields
       assert!(validator.validate(invalid).is_err());
   }

   #[test]
   fn test_validation_error_includes_line_number() {
       let validator = ConfigValidator::new();
       let invalid = "[settings]\ninvalid_key = true";
       let err = validator.validate(invalid).unwrap_err();
       assert!(err.to_string().contains("line 2"));
   }
   ```

3. **Atomic Reload Mechanism**
   ```rust
   #[tokio::test]
   async fn test_reload_applies_atomically() {
       let runtime = RuntimeConfig::new(initial_config());
       let new_config = modified_config();

       runtime.reload(new_config.clone()).await.unwrap();

       // Verify new config is fully applied
       let current = runtime.current().await;
       assert_eq!(current, new_config);
   }

   #[tokio::test]
   async fn test_reload_rollback_on_partial_failure() {
       let runtime = RuntimeConfig::new(initial_config());
       let bad_config = config_that_fails_application();

       let result = runtime.reload(bad_config).await;
       assert!(result.is_err());

       // Original config should still be in effect
       let current = runtime.current().await;
       assert_eq!(current, initial_config());
   }
   ```

4. **File Watcher Integration**
   ```rust
   #[tokio::test]
   async fn test_file_watcher_debounces_rapid_changes() {
       let (tx, mut rx) = mpsc::channel(10);
       let watcher = FileWatcher::new(temp_config_path(), tx);

       // Make 5 rapid changes
       for i in 0..5 {
           write_config(&temp_config_path(), &format!("version = {}", i));
           tokio::time::sleep(Duration::from_millis(100)).await;
       }

       // Wait for debounce period
       tokio::time::sleep(Duration::from_secs(3)).await;

       // Should receive only 1-2 events, not 5
       let events = collect_channel(&mut rx);
       assert!(events.len() <= 2);
   }
   ```

5. **SIGHUP Handler**
   ```rust
   #[tokio::test]
   async fn test_sighup_triggers_reload() {
       let (reload_tx, mut reload_rx) = mpsc::channel(1);
       let handler = SignalHandler::new(reload_tx);

       // Simulate SIGHUP
       handler.handle_signal(Signal::SIGHUP);

       let received = reload_rx.recv().await;
       assert!(received.is_some());
   }
   ```

### Thread Safety Tests
```rust
#[tokio::test]
async fn test_concurrent_reload_requests() {
    let runtime = Arc::new(RuntimeConfig::new(initial_config()));

    // Spawn multiple reload requests
    let handles: Vec<_> = (0..10).map(|i| {
        let rt = runtime.clone();
        let cfg = config_version(i);
        tokio::spawn(async move {
            rt.reload(cfg).await
        })
    }).collect();

    for h in handles {
        let _ = h.await;
    }

    // Should be in a consistent state (one of the versions)
    let current = runtime.current().await;
    assert!(current.version.is_some());
}
```

